#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long first = 1500 - 6 * X - 4 * Y;   // A then B
        long long second = 1500 - 2 * X - 6 * Y;  // B then A
        long long ans = first > second ? first : second;
        printf("%lld\n", ans);
    }
    return 0;
}

